import { Avatar, Box, Button, Card, CardActionArea, CardContent, CardHeader, Divider, IconButton, ListItem, Paper, Typography } from '@material-ui/core'
import { MoreVert } from '@material-ui/icons'
import { makeStyles } from '@material-ui/styles'
import React from 'react'

const useStyle = makeStyles(theme => {
  return {
    root: {
      // '& .MuiCard-root:hover': {
      // boxShadow: 'none',
      // background: 'none'
    },
    avatar: {
      background: '#162276',
      width: theme.spacing(7),
      height: theme.spacing(7),
    }
  }
})

export default function SubjectCards({ subject }) {
  const classes = useStyle()
  return (
    <div>
      <ListItem button>
      <Card elevation={1}>
        <CardActionArea>
          <CardHeader
            avatar={
              <Avatar className={classes.avatar} sizes='medium'>
                P
              </Avatar>
            }
            action={
              <Button>
                <MoreVert />
              </Button>
            }

            title={subject.title}
            subheader={subject.instructor}
          >Webasdasdasd</CardHeader>

          <Divider />
          <CardContent>
            <Typography>
              {subject.body}
            </Typography>
          </CardContent>
          </CardActionArea>
      </Card>
      </ListItem>
    </div>
  )
}
